import React, { useState } from 'react';
import UserForm from './components/UserForm';
import UserList from './components/UserList';
import ProductList from './components/ProductList'; // Добавить импорт
import './styles/main.scss';

function App() {
    const [refreshTrigger, setRefreshTrigger] = useState(0);
    const [userToEdit, setUserToEdit] = useState(null);
    const [activeTab, setActiveTab] = useState('users'); // 'users' или 'products'

    const handleUserAdded = () => {
        setRefreshTrigger(prev => prev + 1);
    };

    const handleUserUpdated = () => {
        setUserToEdit(null);
        setRefreshTrigger(prev => prev + 1);
    };

    const handleEditUser = (user) => {
        setUserToEdit(user);
    };

    return (
        <div className="app">
            <h1>Veresk - Магазин украшений из эпоксидной смолы</h1>

            {/* Добавляем табы для переключения между разделами */}
            <div className="tabs">
                <button 
                    className={`tab ${activeTab === 'users' ? 'active' : ''}`}
                    onClick={() => setActiveTab('users')}
                >
                    👥 Пользователи
                </button>
                <button 
                    className={`tab ${activeTab === 'products' ? 'active' : ''}`}
                    onClick={() => setActiveTab('products')}
                >
                    💎 Товары
                </button>
            </div>

            <div className="content">
                {activeTab === 'users' ? (
                    <>
                        <UserForm 
                            onUserAdded={handleUserAdded}
                            onUserUpdated={handleUserUpdated}
                            userToEdit={userToEdit}
                        />
                        <UserList 
                            onEditUser={handleEditUser}
                            refreshTrigger={refreshTrigger}
                        />
                    </>
                ) : (
                    <ProductList /> // Добавляем список товаров
                )}
            </div>
        </div>
    );
}

export default App;
